/**
 * @summary Get pet timeline updates
 */
export const getListPetUpdatesUrl = (petId: string) => {
  return `/api/pets/${petId}/updates`;
};

export const listPetUpdates = async (
  petId: string,
  options?: RequestInit,
): Promise<PetUpdateItem[]> => {
  return customFetch<PetUpdateItem[]>(getListPetUpdatesUrl(petId), {
    ...options,
    method: "GET",
  });
};

export const getListPetUpdatesQueryKey = (petId: string) => {
  return [`/api/pets/${petId}/updates`] as const;
};

export const getListPetUpdatesQueryOptions = <
  TData = Awaited<ReturnType<typeof listPetUpdates>>,
  TError = ErrorType<unknown>,
>(
  petId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listPetUpdates>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListPetUpdatesQueryKey(petId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listPetUpdates>>> = ({
    signal,
  }) => listPetUpdates(petId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!petId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listPetUpdates>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListPetUpdatesQueryResult = NonNullable<
  Awaited<ReturnType<typeof listPetUpdates>>
>;
export type ListPetUpdatesQueryError = ErrorType<unknown>;

